"""Тесты хранилища реестра: загрузка из файла, сохранение в файл."""from __future__ import annotationsimport jsonfrom pathlib import Pathimport pytestfrom src.modules.llm_models_registry.providers.llm_model_store import LLMModelStoreREGISTRY_FILENAME = "llm_models_registry.json"def test_load_missing_file_data_empty(tmp_path: Path) -> None:    """При отсутствии файла после load() store.data == {}."""    store = LLMModelStore(store_file_path=tmp_path / REGISTRY_FILENAME)    store.load()    assert store.data == {}def test_load_legacy_json_array_ignored(tmp_path: Path) -> None:    """Старый list-формат больше не поддерживается: загрузка даёт пустой store.data."""    path = tmp_path / REGISTRY_FILENAME    payload = [        {"provider": "openai", "name": "gpt-4", "enabled": True},    ]    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")    store = LLMModelStore(store_file_path=path)    store.load()    assert store.data == {}    persisted = json.loads(path.read_text(encoding="utf-8"))    assert isinstance(persisted, list)def test_load_valid_json_object_fills_data(tmp_path: Path) -> None:    """Валидный JSON-объект загружается как есть в store.data."""    path = tmp_path / REGISTRY_FILENAME    payload = {        "openai@gpt-4": {"provider": "openai", "name": "gpt-4", "enabled": True},    }    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")    store = LLMModelStore(store_file_path=path)    store.load()    assert len(store.data) == 1    assert "openai@gpt-4" in store.datadef test_load_invalid_json_data_empty(tmp_path: Path) -> None:    """При невалидном JSON после load() store.data == {}."""    path = tmp_path / REGISTRY_FILENAME    path.write_text("{ invalid", encoding="utf-8")    store = LLMModelStore(store_file_path=path)    store.load()    assert store.data == {}def test_save_creates_file_and_content_matches(tmp_path: Path) -> None:    """save() создаёт файл, содержимое совпадает с store.data."""    path = tmp_path / REGISTRY_FILENAME    store = LLMModelStore(store_file_path=path)    store.data = {        "test@model-1": {"provider": "test", "name": "model-1", "enabled": True},    }    store.save()    assert path.exists()    data = json.loads(path.read_text(encoding="utf-8"))    assert data == store.data    assert data["test@model-1"]["provider"] == "test"    assert data["test@model-1"]["name"] == "model-1"def test_save_creates_directory_if_needed(tmp_path: Path) -> None:    """save() создаёт каталог при необходимости."""    subdir = tmp_path / "sub" / "dir"    store = LLMModelStore(store_file_path=subdir / REGISTRY_FILENAME)    store.data = {}    store.save()    assert (subdir / REGISTRY_FILENAME).exists()